/// Photo pair capture state machine
/// Enforces AC-A.4.2: Overview → Close-up → Additional sequence
enum PhotoPairState {
  none,        // No photos captured yet
  overview,    // Overview photo captured, close-up enabled
  closeup,     // Close-up captured, additional enabled
  additional,  // Additional photo(s) captured, can capture more additional
}

/// Photo pair manager - Enforces photo-pair workflow
/// Manages state transitions and photo-pair ID generation
class PhotoPairManager extends ChangeNotifier {
  static const _uuid = Uuid();

  // Current state
  PhotoPairState _currentState = PhotoPairState.none;
  String? _currentPhotoPairId;

  // Photo counts for current pair
  int _overviewCount = 0;
  int _closeupCount = 0;
  int _additionalCount = 0;

  // Getters
  PhotoPairState get currentState => _currentState;
  String? get currentPhotoPairId => _currentPhotoPairId;
  int get overviewCount => _overviewCount;
  int get closeupCount => _closeupCount;
  int get additionalCount => _additionalCount;
  int get totalPhotosInPair => _overviewCount + _closeupCount + _additionalCount;

  /// Check if overview photo is allowed
  bool get canCaptureOverview =>
      _currentState == PhotoPairState.none ||
      _currentState == PhotoPairState.additional;

  /// Check if close-up photo is allowed (AC-A.4.2: UI blocks close-up until overview)
  bool get canCaptureCloseup =>
      _currentState == PhotoPairState.overview ||
      _currentState == PhotoPairState.closeup ||
      _currentState == PhotoPairState.additional;

  /// Check if additional photo is allowed
  bool get canCaptureAdditional =>
      _currentState == PhotoPairState.closeup ||
      _currentState == PhotoPairState.additional;

  /// Get current step number (1-3) for progress indicator (AC-A.4.3, AC-A.4.10)
  int get currentStep {
    switch (_currentState) {
      case PhotoPairState.none:
        return 1; // About to capture overview
      case PhotoPairState.overview:
        return 2; // About to capture close-up
      case PhotoPairState.closeup:
      case PhotoPairState.additional:
        return 3; // Capturing additional photos
    }
  }

  /// Get step description for UI (AC-A.4.3)
  String get stepDescription {
    switch (_currentState) {
      case PhotoPairState.none:
        return 'Step 1 of 3: Overview';
      case PhotoPairState.overview:
        return 'Step 2 of 3: Close-up';
      case PhotoPairState.closeup:
      case PhotoPairState.additional:
        return 'Step 3 of 3: Additional';
    }
  }

  /// Get progress fraction for progress ring (0.0 - 1.0)
  double get progress {
    switch (_currentState) {
      case PhotoPairState.none:
        return 0.0;
      case PhotoPairState.overview:
        return 0.33;
      case PhotoPairState.closeup:
        return 0.66;
      case PhotoPairState.additional:
        return 1.0;
    }
  }

  /// Start a new photo pair (generates new photo_pair_id)
  /// Called when capturing overview photo
  String startNewPhotoPair() {
    _currentPhotoPairId = _uuid.v4();
    _currentState = PhotoPairState.none;
    _overviewCount = 0;
    _closeupCount = 0;
    _additionalCount = 0;
    debugPrint('[PhotoPairManager] Started new photo pair: $_currentPhotoPairId');
    notifyListeners();
    return _currentPhotoPairId!;
