  final void Function(PhotoFileInfo photo)? onPhotoTap;
  final Future<void> Function(String? pairId, int oldIndex, int newIndex)? onReorderWithinPair;
  final Future<void> Function(String? pairId, int index, int delta)? onMoveWithinPair;
  final Future<void> Function(PhotoFileInfo photo)? onRetake;

  const PhotoGalleryWidget({
