    required this.photos,
    this.onPhotoTap,
    this.onReorderWithinPair,
    this.onMoveWithinPair,
    this.onRetake,
  });

  @override
  Widget build(BuildContext context) {
    if (photos.isEmpty) {
      return Center(
        child: Text(
          'No photos captured yet',
          style: Theme.of(context).textTheme.bodyMedium,
        ),
      );
    }

    final grouped = _groupPhotos(photos);

    return ListView.separated(
      padding: const EdgeInsets.all(16),
      itemCount: grouped.length,
      separatorBuilder: (_, __) => const SizedBox(height: 16),
      itemBuilder: (context, index) {
        final group = grouped[index];
        final groupTitle = group.pairId == null
            ? 'Ungrouped Photos'
            : 'Photo Pair ${group.sequenceIndex + 1}';
        final subtitle = _buildSubtitle(group.photos);

        return Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text(
              groupTitle,
              style: Theme.of(context).textTheme.titleMedium,
            ),
            if (subtitle.isNotEmpty)
              Padding(
                padding: const EdgeInsets.only(top: 4, bottom: 8),
                child: Text(
                  subtitle,
                  style: Theme.of(context).textTheme.bodySmall,
                ),
              )
            else
              const SizedBox(height: 8),
            _buildReorderableGroup(context, group),
          ],
        );
      },
    );
  }

  Widget _buildReorderableGroup(BuildContext context, _PhotoPairGroup group) {
    return ReorderableListView.builder(
      key: ValueKey(group.pairId ?? 'ungrouped'),
      shrinkWrap: true,
      physics: const NeverScrollableScrollPhysics(),
      itemCount: group.photos.length,
      buildDefaultDragHandles: false,
      padding: EdgeInsets.zero,
      itemBuilder: (context, index) {
        final photo = group.photos[index];
        final canMoveUp = index > 0;
        final canMoveDown = index < group.photos.length - 1;

        return ReorderableDragStartListener(
          key: ValueKey(photo.id ?? photo.filePath),
          index: index,
          child: _GalleryTile(
            photo: photo,
            onTap: onPhotoTap != null ? () => onPhotoTap!(photo) : null,
            canMoveUp: canMoveUp,
            canMoveDown: canMoveDown,
            onMoveUp: canMoveUp && onMoveWithinPair != null
                ? () => unawaited(onMoveWithinPair!(group.pairId, index, -1))
                : null,
            onMoveDown: canMoveDown && onMoveWithinPair != null
                ? () => unawaited(onMoveWithinPair!(group.pairId, index, 1))
                : null,
            onRetake: onRetake != null ? () => onRetake!(photo) : null,
          ),
        );
      },
      onReorder: (oldIndex, newIndex) {
        if (onReorderWithinPair == null) return;
        var targetIndex = newIndex;
        if (newIndex > oldIndex) {
