        }
        unawaited(onReorderWithinPair!(group.pairId, oldIndex, targetIndex));
      },
    );
  }

  List<_PhotoPairGroup> _groupPhotos(List<PhotoFileInfo> items) {
    final List<_PhotoPairGroup> pairGroups = [];
    final List<PhotoFileInfo> ungrouped = [];
