  String _buildSubtitle(List<PhotoFileInfo> photos) {
    if (photos.isEmpty) return '';

    final counts = <PhotoType, int>{};
    for (final photo in photos) {
      final type = photo.photoType;
      if (type == null) continue;
      counts[type] = (counts[type] ?? 0) + 1;
